items.configValue:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "WarehouseList",
  "description": "A list of commerce warehouses generated by AI.",
  "type": "object",
  "properties": {
    "warehouses": {
      "type": "array",
      "description": "An array of generated warehouse objects.",
      "items": {
        "title": "Warehouse",
        "type": "object",
        "properties": {
          "name": {
            "description": "The localized name of the warehouse.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "description": {
            "description": "The localized description of the warehouse.",
            "type": "object",
            "additionalProperties": {
              "type": "string"
            }
          },
          "country": {
            "description": "The two-letter country code for the warehouse's location.",
            "type": "string",
            "pattern": "^[A-Z]{2}$"
          },
          "region": {
            "description": "The two-letter region or state code for the warehouse's location.",
            "type": "string",
            "pattern": "^[A-Z]{2}$"
          },
          "city": {
            "description": "The city where the warehouse is located.",
            "type": "string"
          },
          "street1": {
            "description": "The first line of the street address.",
            "type": "string"
          },
          "zip": {
            "description": "The postal code for the warehouse's location.",
            "type": "string"
          },
          "latitude": {
            "description": "The latitude of the warehouse's location.",
            "type": "number",
            "minimum": -90,
            "maximum": 90
          },
          "longitude": {
            "description": "The longitude of the warehouse's location.",
            "type": "number",
            "minimum": -180,
            "maximum": 180
          },
          "active": {
            "description": "Whether the warehouse is active.",
            "type": "boolean"
          }
        },
        "required": [
          "name",
          "country",
          "region",
          "city",
          "street1",
          "zip",
          "latitude",
          "longitude",
          "active"
        ]
      }
    }
  },
  "required": [
    "warehouses"
  ]
}
